const item = $input.first().json;
const body = item.body;
const payload =
  body !== undefined && body !== null && typeof body === 'object' && !Array.isArray(body)
    ? { ...body }
    : { ...item };
return [{ json: payload }];

/**
 * Texto base = simulación de "PDF" ya extraído a texto.
 * Reemplazá el contenido de TEXTO_KB_PDF por el extracto real de tu PDF.
 */
const TEXTO_KB_PDF = `
=== CASETODO CARLOS RUIZ — GUÍA RÁPIDA (INTERNO) ===

Qué es un casetón: módulo prefabricado para obra (oficina, vestuario, bodega temporal). Materiales y medidas estándar según catálogo.

Servicios: VENTA de casetones y ALQUILER por periodos (día / semana / mes según disponibilidad y zona). No alquilamos maquinaria ni andamios.

Medidas frecuentes (ejemplos): 2x2 m, 2x3 m, 3x6 m. Medidas especiales: consultar stock y transporte.

Precios orientativos (sujetos a confirmación): alquiler desde referencia según tamaño y ciudad; cotización formal requiere dirección de obra o ciudad, fechas y cantidad.

Zona: atención principal Colombia; envíos/traslado dependen de distancia.

Plazos: disponibilidad variable; en temporada alta puede haber lista de espera.

Cómo cotizar: nombre, teléfono, ciudad de la obra, medidas deseadas o módulos, fecha de inicio y duración aproximada.

Política: no damos asesoría legal ni estructural de edificios fijos; solo producto casetón.

Contacto: equipo comercial revisa solicitudes vía web y WhatsApp.
`.trim();

const SEP = '\n---CHUNK---\n';
const rawChunks = TEXTO_KB_PDF.split(/\n{2,}/).map((s) => s.trim()).filter(Boolean);
const chunks = rawChunks.length ? rawChunks : [TEXTO_KB_PDF];

const j = $input.first().json;
return [{ json: { ...j, _kbChunks: chunks, _kbVersion: 'demo-pdf-v1' } }];

const j = $input.first().json;
const q = String(j.mensaje || j.message || '').toLowerCase().trim();
const chunks = Array.isArray(j._kbChunks) ? j._kbChunks : [];

function score(text, query) {
  if (!query) return 0;
  const words = query.split(/[^a-záéíóúñ0-9]+/i).filter((w) => w.length > 2);
  const t = text.toLowerCase();
  let s = 0;
  for (const w of words) {
    if (t.includes(w)) s += 2;
  }
  if (/caseton|casetón|caseta|obra|alquiler|venta|precio|medida|cotiz/.test(t) && /caseton|casetón|caseta|obra|alquiler|venta|precio|medida|cotiz/.test(query)) s += 1;
  return s;
}

const ranked = chunks
  .map((c, i) => ({ i, c, s: score(c, q) }))
  .sort((a, b) => b.s - a.s);

const top = ranked.filter((x) => x.s > 0).slice(0, 5).map((x) => x.c);
const picked = top.length ? top : ranked.slice(0, 3).map((x) => x.c);
const contexto = picked.join('\n\n———\n\n');

const systemPrompt = `Eres el asistente virtual de Casetodo Carlos Ruiz. Solo vendemos y alquilamos casetones. Basa la respuesta SOLO en el CONTEXTO. Si falta información, dilo y pide datos para cotizar o deriva al equipo. Español, breve. No inventes precios ni plazos no presentes en el contexto.`;

const userPrompt = `PREGUNTA DEL CLIENTE:\n${String(j.mensaje || '').trim() || '(vacío)'}\n\nCONTEXTO DE LA EMPRESA (extraído de documentos internos):\n${contexto || '(sin coincidencias en la guía; responde que no hay dato en la guía y pide aclaración o contacto).'}`;

return [
  {
    json: {
      ...j,
      _ragContexto: contexto,
      _ragCitas: picked.map((c) => c.slice(0, 160).replace(/\s+/g, ' ') + (c.length > 160 ? '…' : '')),
      systemPrompt,
      userPrompt,
      _openaiBody: {
        model: 'gpt-4o-mini',
        temperature: 0.35,
        messages: [
          { role: 'system', content: systemPrompt },
          { role: 'user', content: userPrompt }
        ]
      }
    }
  }
];

const j = $input.first().json;
const ctx = String(j._ragContexto || '').trim();
const q = String(j.mensaje || '').trim();

let reply = '';
if (!q) {
  reply =
    'Hola, soy el asistente de Casetodo Carlos Ruiz. Estoy para ayudarte con **venta y alquiler de casetones**. ¿Qué medidas o ciudad de obra necesitás?';
} else if (!ctx) {
  reply =
    'Hola. Con lo que contás no encontré una coincidencia clara en nuestra guía interna. Recordá que en Casetodo solo trabajamos **casetones (venta y alquiler)**. Pasame medidas aproximadas, ciudad y si es alquiler o compra, y lo vemos con el equipo.';
} else {
  reply = [
    'Hola, gracias por tu consulta.',
    '',
    'Según la información que manejamos sobre casetones (venta y alquiler):',
    '',
    ctx.slice(0, 2800),
    '',
    'Si necesitás **cotización con precio confirmado**, indicá ciudad de la obra, medidas o referencia del módulo y fechas aproximadas; un asesor lo valida.'
  ].join('\n');
}

return [{ json: { ...j, reply, citas: j._ragCitas || [], modo: 'demo_reglas' } }];
